  rdy_o <= '1' when InCnt - OutCnt /= 2 else '0';

  p_input : process(clk_in_i)
  begin
    if rising_edge(clk_in_i) then
      if (rst_in_i = in_rst_pol_g) or (rst_out_i = out_rst_pol_g) then
        InCnt <= (others => '0');
      else
        if vld_i = '1' and InCnt - OutCnt /= 2 then
          InCnt         <= InCnt + 1;
