10	-- see Library/Python/TbGenerator
11	
12	------------------------------------------------------------
13	-- Libraries
14	------------------------------------------------------------
15	library ieee;
16	use ieee.std_logic_1164.all;
17	use ieee.numeric_std.all;
18	use ieee.math_real.all;
19	
20	library work;
21	use work.psi_tb_compare_pkg.all;
22	use work.psi_tb_txt_util.all;
23	
24	------------------------------------------------------------
25	-- Entity Declaration
26	------------------------------------------------------------
27	entity psi_common_sync_cc_n2xn_tb is
28	  generic(
29	    ratio_g : integer := 2
30	  );
31	end entity;
32	
33	------------------------------------------------------------
34	-- Architecture
35	------------------------------------------------------------
36	architecture sim of psi_common_sync_cc_n2xn_tb is
37	  -- *** Fixed Generics ***
38	
39	  -- *** Not Assigned Generics (default values) ***
40	  constant width_g : integer := 8;
41	
42	  -- *** TB Control ***
43	  signal TbRunning            : boolean                  := True;
44	  signal NextCase             : integer                  := -1;
45	  signal ProcessDone          : std_logic_vector(0 to 1) := (others => '0');
46	  constant AllProcessesDone_c : std_logic_vector(0 to 1) := (others => '1');
47	  constant TbProcNr_stim_c    : integer                  := 0;
48	  constant TbProcNr_check_c   : integer                  := 1;
49	
50	  -- *** DUT Signals ***
51	  signal clk_i   : std_logic                              := '1';
52	  signal rst_i   : std_logic                              := '1';
53	  signal vld_i   : std_logic                              := '0';
54	  signal rdy_o   : std_logic                              := '0';
55	  signal dat_i  : std_logic_vector(width_g - 1 downto 0) := (others => '0');
56	  signal clk_o  : std_logic                              := '1';
57	  signal rst_o  : std_logic                              := '1';
58	  signal vld_o  : std_logic                              := '0';
59	  signal rdy_i  : std_logic                              := '0';
60	  signal dat_o : std_logic_vector(width_g - 1 downto 0) := (others => '0');
61	
62	  -- Handwritten
63	  constant ClkFreqIn : real    := real(100e6);
64	  signal done        : boolean := False;
65	  signal testcase    : integer := -1;
66	
67	begin
68	  ------------------------------------------------------------
69	  -- DUT Instantiation
70	  ------------------------------------------------------------
71	  i_dut : entity work.psi_common_sync_cc_n2xn
72	    port map(
73	      clk_in_i   => clk_i,
74	      rst_in_i   => rst_i,
75	      vld_i   => vld_i,
76	      rdy_o   => rdy_o,
77	      dat_i  => dat_i,
78	      clk_out_i  => clk_o,
79	      rst_out_i  => rst_o,
80	      vld_o  => vld_o,
81	      rdy_i  => rdy_i,
82	      dat_o => dat_o
83	    );
84	
85	  ------------------------------------------------------------
86	  -- Testbench Control !DO NOT EDIT!
87	  ------------------------------------------------------------
88	  p_tb_control : process
89	  begin
90	    wait until rst_i = '0' and rst_o = '0';
91	    wait until ProcessDone = AllProcessesDone_c;
92	    TbRunning <= false;
93	    wait;
94	  end process;
95	
96	  ------------------------------------------------------------
97	  -- Clocks !DO NOT EDIT!
98	  ------------------------------------------------------------
99	  p_clock_InClk : process
100	    constant Frequency_c : real := ClkFreqIn;
101	  begin
102	    while TbRunning loop
103	      wait for 0.5 * (1 sec) / Frequency_c;
104	      clk_i <= not clk_i;
105	    end loop;
106	    wait;
107	  end process;
108	
109	  p_clock_OutClk : process
110	    constant Frequency_c : real := ClkFreqIn * real(ratio_g);
111	  begin
112	    while TbRunning loop
113	      wait for 0.5 * (1 sec) / Frequency_c;
114	      clk_o <= not clk_o;
115	    end loop;
116	    wait;
117	  end process;
118	
119	  ------------------------------------------------------------
120	  -- Resets
121	  ------------------------------------------------------------
122	  p_rst_InRst : process
123	  begin
124	    wait for 1 us;
125	    -- Wait for two clk edges to ensure reset is active for at least one edge
126	    wait until rising_edge(clk_i);
127	    wait until rising_edge(clk_i);
128	    rst_i <= '0';
129	    wait;
130	  end process;
131	
132	  p_rst_OutRst : process
133	  begin
134	    wait for 1 us;
135	    -- Wait for two clk edges to ensure reset is active for at least one edge
136	    wait until rising_edge(clk_o);
137	    wait until rising_edge(clk_o);
138	    rst_o <= '0';
139	    wait;
140	  end process;
141	
142	  ------------------------------------------------------------
143	  -- Processes
144	  ------------------------------------------------------------
145	  -- *** stim ***
146	  p_stim : process
147	  begin
148	    -- start of process !DO NOT EDIT
149	    wait until rst_i = '0' and rst_o = '0';
150	
151	    -- Test Single Beats		
152	    print(">> Single Beats");
153	    testcase <= 0;
154	    wait until rising_edge(clk_i);
155	    for del in 3 downto 1 loop
156	      for val in 1 to 4 loop
157	        dat_i <= std_logic_vector(to_unsigned(val, width_g));
158	        vld_i  <= '1';
159	        wait until rising_edge(clk_i);
160	        vld_i  <= '0';
161	        for j in 0 to del - 1 loop
162	          wait until rising_edge(clk_i);
163	        end loop;
164	      end loop;
165	      wait until rising_edge(clk_i);
166	      wait until rising_edge(clk_i);
167	      wait until rising_edge(clk_i);
168	      wait until rising_edge(clk_i);
169	    end loop;
170	    if done /= true then
171	      wait until done = true;
172	    end if;
173	
174	    -- Test Streaming		
175	    print(">> Streaming");
176	    testcase <= 1;
177	    wait until rising_edge(clk_i);
178	    vld_i    <= '1';
179	    for val in 1 to 8 loop
180	      dat_i <= std_logic_vector(to_unsigned(val, width_g));
181	      wait until rising_edge(clk_i);
182	    end loop;
183	    vld_i    <= '0';
184	    if done /= true then
185	      wait until done = true;
186	    end if;
187	
188	    -- Test Back Pressure		
189	    print(">> Back Pressure");
190	    testcase <= 2;
191	    wait until rising_edge(clk_i);
192	    for inDel in 3 downto 0 loop
193	      for outDel in 0 to 20 loop
194	        for val in 1 to 8 loop
195	          vld_i  <= '1';
196	          dat_i <= std_logic_vector(to_unsigned(val, width_g));
197	          wait until rising_edge(clk_i) and rdy_o = '1';
198	          for j in 0 to inDel - 1 loop
199	            vld_i <= '0';
200	            wait until rising_edge(clk_i);
201	          end loop;
202	        end loop;
203	        vld_i <= '0';
204	        wait for 1 us;
205	        wait until rising_edge(clk_i);
206	      end loop;
207	    end loop;
208	    if done /= true then
209	      wait until done = true;
210	    end if;
211	
212	    -- Valid does not wait for Ready	
213	    print(">> Valid does not wait for Ready");
214	    testcase <= 3;
215	    wait until rising_edge(clk_i);
216	    for outDel in 0 to 10 loop
217	      for val in 1 to 4 loop
218	        vld_i  <= '1';
219	        dat_i <= std_logic_vector(to_unsigned(val, width_g));
220	        wait until rising_edge(clk_i) and rdy_o = '1';
221	      end loop;
222	      vld_i <= '0';
223	      wait for 1 us;
224	      wait until rising_edge(clk_i);
225	    end loop;
226	    if done /= true then
227	      wait until done = true;
228	    end if;
229	
230	    -- end of process !DO NOT EDIT!
231	    ProcessDone(TbProcNr_stim_c) <= '1';
232	    wait;
233	  end process;
234	
235	  -- *** check ***
236	  p_check : process
237	  begin
238	    -- start of process !DO NOT EDIT
239	    wait until rst_i = '0' and rst_o = '0';
240	
241	    -- Test Single Beats
242	    wait until testcase = 0;
243	    done   <= False;
244	    rdy_i <= '1';
245	    for del in 3 downto 1 loop
246	      for val in 1 to 4 loop
247	        wait until rising_edge(clk_o) and vld_o = '1';
248	        StdlvCompareInt(val, dat_o, "Wrong Data");
249	        wait until rising_edge(clk_o);
250	        assert vld_o = '0' report "###ERROR###: vld_o did not go low" severity error;
251	      end loop;
252	    end loop;
253	    done   <= True;
254	
255	    -- Test Streaming
256	    wait until testcase = 1;
257	    done   <= False;
258	    rdy_i <= '1';
259	    for val in 1 to 8 loop
260	      wait until rising_edge(clk_o) and vld_o = '1';
261	      StdlvCompareInt(val, dat_o, "Wrong Data");
262	      wait until rising_edge(clk_o);
263	      assert vld_o = '0' report "###ERROR###: vld_o did not go low" severity error;
264	    end loop;
265	    done   <= True;
266	
267	    -- Test Back Pressure
268	    wait until testcase = 2;
269	    done <= False;
270	    for inDel in 3 downto 0 loop
271	      for outDel in 0 to 20 loop
272	        for val in 1 to 8 loop
