  -- Resets
  ------------------------------------------------------------
  p_rst_InRst : process
  begin
    wait for 1 us;
    -- Wait for two clk edges to ensure reset is active for at least one edge
    wait until rising_edge(clk_i);
    wait until rising_edge(clk_i);
    rst_i <= '0';
    wait;
  end process;

  p_rst_OutRst : process
  begin
    wait for 1 us;
    -- Wait for two clk edges to ensure reset is active for at least one edge
    wait until rising_edge(clk_o);
    wait until rising_edge(clk_o);
    rst_o <= '0';
    wait;
  end process;

  ------------------------------------------------------------
  -- Processes
  ------------------------------------------------------------
  -- *** stim ***
  p_stim : process
  begin
    -- start of process !DO NOT EDIT
    wait until rst_i = '0' and rst_o = '0';

    -- Normal Operation		
    print(">> Normal Operation");
    testcase <= 0;
    wait until rising_edge(clk_i);
    for del in 4 downto 1 loop
      for val in 1 to 8 loop
        dat_i <= std_logic_vector(to_unsigned(val, width_g));
        vld_i  <= '1';
        wait until rising_edge(clk_i);
        vld_i  <= '0';
        wait for 1 ns;
        for j in 0 to del * ratio_g - 2 loop
          wait until rising_edge(clk_i);
        end loop;
      end loop;
      wait until rising_edge(clk_i);
      wait until rising_edge(clk_i);
      wait until rising_edge(clk_i);
      wait until rising_edge(clk_i);
    end loop;
    if done /= true then
      wait until done = true;
    end if;

    -- Test Back Pressure		
    print(">> Back Pressure");
    testcase <= 1;
    wait until rising_edge(clk_i);
    for inDel in 20 downto 0 loop
      for outDel in 0 to 4 loop
        for val in 1 to 8 loop
          vld_i  <= '1';
          dat_i <= std_logic_vector(to_unsigned(val, width_g));
          wait until rising_edge(clk_i) and rdy_o = '1';
          for j in 0 to inDel - 1 loop
            vld_i <= '0';
            wait until rising_edge(clk_i);
          end loop;
        end loop;
        vld_i <= '0';
        wait for 1 us;
        wait until rising_edge(clk_i);
      end loop;
    end loop;
    if done /= true then
      wait until done = true;
    end if;

    -- Valid does not wait for Ready	
    print(">> Valid does not wait for Ready");
    testcase <= 2;
    wait until rising_edge(clk_i);
    for outDel in 0 to 10 loop
      for val in 1 to 4 loop
        vld_i  <= '1';
        dat_i <= std_logic_vector(to_unsigned(val, width_g));
        wait until rising_edge(clk_i) and rdy_o = '1';
      end loop;
      vld_i <= '0';
      wait for 1 us;
      wait until rising_edge(clk_i);
    end loop;
    if done /= true then
      wait until done = true;
    end if;

    -- end of process !DO NOT EDIT!
    ProcessDone(TbProcNr_stim_c) <= '1';
    wait;
  end process;

  -- *** check ***
  p_check : process
  begin
    -- start of process !DO NOT EDIT
    wait until rst_i = '0' and rst_o = '0';

    -- Test Normal Operation
    wait until testcase = 0;
    done   <= False;
    rdy_i <= '1';
    for del in 4 downto 1 loop
      for val in 1 to 8 loop
        wait until rising_edge(clk_o) and vld_o = '1';
        StdlvCompareInt(val, dat_o, "Wrong Data");
      end loop;
    end loop;
    done   <= True;

    -- Test Back Pressure
    wait until testcase = 1;
    done <= False;
    for inDel in 20 downto 0 loop
      for outDel in 0 to 4 loop
        for val in 1 to 8 loop
          rdy_i <= '1';
          wait until rising_edge(clk_o) and vld_o = '1';
          StdlvCompareInt(val, dat_o, "Wrong Data");
          for j in 0 to outDel - 1 loop
            rdy_i <= '0';
            wait until rising_edge(clk_o);
          end loop;
        end loop;
      end loop;
    end loop;
    done <= True;

    -- Valid does not wait for Ready
    wait until testcase = 2;
    done   <= False;
    rdy_i <= '0';
    wait until rising_edge(clk_o);
    for outDel in 0 to 10 loop
      for val in 1 to 4 loop
        if vld_o /= '1' then
          wait until vld_o = '1';
        end if;
        for i in 0 to outDel - 1 loop
          wait until rising_edge(clk_o);
          assert vld_o = '1' report "###ERROR###: vld_o went low" severity error;
        end loop;
        wait for 1 ns;
        rdy_i <= '1';
        StdlvCompareInt(val, dat_o, "Wrong Data");
        wait until rising_edge(clk_o);
        wait for 1 ns;
        rdy_i <= '0';
      end loop;
    end loop;
    done   <= True;

    -- end of process !DO NOT EDIT!
    ProcessDone(TbProcNr_check_c) <= '1';
    wait;
  end process;

end;

